import hashlib
import time
import uuid
from collections import defaultdict

class InteractionTracker:
    def __init__(self):
        self.user_interactions = defaultdict(list)  # {hashed_user_id: [interaction_data]}
        self.interaction_types = set()

    def hash_user_id(self, user_id):
        """Hashes the user ID for anonymization."""
        hashed_id = hashlib.sha256(str(user_id).encode('utf-8')).hexdigest()
        return hashed_id

    def anonymize_data(self, interaction_type, data):
        """Anonymizes sensitive data based on interaction type."""
        anonymized_data = data.copy()
        if interaction_type == "upload":
            # Example: Anonymize file name but keep file type
            if "file_name" in anonymized_data:
                file_extension = anonymized_data["file_name"].split(".")[-1] if "." in anonymized_data["file_name"] else ""
                anonymized_data["file_name"] = hashlib.sha256(str(uuid.uuid4()).encode('utf-8')).hexdigest() + "." + file_extension
        elif interaction_type == "settings_change":
            #Example: Hash the old and new values
            if "old_value" in anonymized_data:
                anonymized_data["old_value"] = hashlib.sha256(str(anonymized_data["old_value"]).encode('utf-8')).hexdigest()
            if "new_value" in anonymized_data:
                anonymized_data["new_value"] = hashlib.sha256(str(anonymized_data["new_value"]).encode('utf-8')).hexdigest()

        return anonymized_data

    def track_interaction(self, user_id, interaction_type, data):
        """Tracks a user interaction, anonymizing data as needed."""
        if not isinstance(user_id, (int, str)):
            raise ValueError("User ID must be an integer or string.")

        if not isinstance(interaction_type, str):
            raise ValueError("Interaction type must be a string.")

        if not isinstance(data, dict):
            raise ValueError("Interaction data must be a dictionary.")

        self.interaction_types.add(interaction_type)
        hashed_user_id = self.hash_user_id(user_id)
        anonymized_data = self.anonymize_data(interaction_type, data)
        interaction_record = {
            "type": interaction_type,
            "timestamp": time.time(),
            "data": anonymized_data
        }
        self.user_interactions[hashed_user_id].append(interaction_record)

    def get_user_interactions(self, user_id):
        """Retrieves interactions for a user."""
        hashed_user_id = self.hash_user_id(user_id)
        return self.user_interactions.get(hashed_user_id, [])

    def get_interaction_summary(self):
        """Provides a summary of interactions (e.g., counts by type)."""
        summary = {}
        for user_id, interactions in self.user_interactions.items():
            for interaction in interactions:
                interaction_type = interaction["type"]
                if interaction_type not in summary:
                    summary[interaction_type] = 0
                summary[interaction_type] += 1
        return summary

    def remove_user_data(self, user_id):
        """Removes all data associated with a user."""
        hashed_user_id = self.hash_user_id(user_id)
        if hashed_user_id in self.user_interactions:
            del self.user_interactions[hashed_user_id]

    def get_all_interaction_types(self):
        """Returns a set of all interaction types."""
        return self.interaction_types

if __name__ == '__main__':
    tracker = InteractionTracker()

    # Example Usage
    user_id_1 = 123
    user_id_2 = "abc"

    tracker.track_interaction(user_id_1, "like", {"item_id": 456})
    tracker.track_interaction(user_id_1, "rating", {"item_id": 456, "rating": 5})
    tracker.track_interaction(user_id_2, "upload", {"file_name": "document.pdf", "file_size": 1024})
    tracker.track_interaction(user_id_2, "settings_change", {"setting_name": "privacy", "old_value": "public", "new_value": "private"})

    print("User 1 Interactions:", tracker.get_user_interactions(user_id_1))
    print("User 2 Interactions:", tracker.get_user_interactions(user_id_2))
    print("Interaction Summary:", tracker.get_interaction_summary())
    print("All Interaction Types:", tracker.get_all_interaction_types())

    tracker.remove_user_data(user_id_1)
    print("User 1 Interactions after removal:", tracker.get_user_interactions(user_id_1))

import hashlib
import time
import uuid
from collections import defaultdict

class InteractionTracker:
    def __init__(self):
        self.user_interactions = defaultdict(list)  # {hashed_user_id: [interaction_data]}
        self.interaction_types = set()

    def hash_user_id(self, user_id):
        """Hashes the user ID for anonymization."""
        hashed_id = hashlib.sha256(str(user_id).encode('utf-8')).hexdigest()
        return hashed_id

    def anonymize_data(self, interaction_type, data):
        """Anonymizes sensitive data based on interaction type."""
        anonymized_data = data.copy()  # Create a copy to avoid modifying the original

        if interaction_type == "upload":
            # Example: Anonymize file names
            if "file_name" in anonymized_data:
                anonymized_data["file_name"] = hashlib.sha256(anonymized_data["file_name"].encode('utf-8')).hexdigest()
        elif interaction_type == "settings_change":
            # Example: Anonymize specific setting values
            if "setting_name" in anonymized_data and anonymized_data["setting_name"] == "email":
                anonymized_data["new_value"] = "anonymized_email"

        return anonymized_data

    def track_interaction(self, user_id, interaction_type, data):
        """Tracks a user interaction, anonymizing data as needed."""
        if not isinstance(user_id, (int, str)):
            raise ValueError("User ID must be an integer or string.")

        if not isinstance(interaction_type, str):
            raise ValueError("Interaction type must be a string.")

        if not isinstance(data, dict):
            raise ValueError("Interaction data must be a dictionary.")

        self.interaction_types.add(interaction_type)
        hashed_user_id = self.hash_user_id(user_id)
        anonymized_data = self.anonymize_data(interaction_type, data)

        interaction_data = {
            "interaction_id": str(uuid.uuid4()),  # Unique ID for each interaction
            "timestamp": time.time(),
            "interaction_type": interaction_type,
            "data": anonymized_data
        }

        self.user_interactions[hashed_user_id].append(interaction_data)

    def get_user_interactions(self, user_id):
        """Retrieves interactions for a user (hashed ID)."""
        hashed_user_id = self.hash_user_id(user_id)
        return self.user_interactions.get(hashed_user_id, [])

    def get_all_interactions_by_type(self, interaction_type):
        """Retrieves all interactions of a specific type."""
        interactions = []
        for user_interactions in self.user_interactions.values():
            for interaction in user_interactions:
                if interaction["interaction_type"] == interaction_type:
                    interactions.append(interaction)
        return interactions

    def get_interaction_types(self):
        """Returns the set of all interaction types."""
        return self.interaction_types

    def clear_user_data(self, user_id):
        """Deletes all interaction data for a user."""
        hashed_user_id = self.hash_user_id(user_id)
        if hashed_user_id in self.user_interactions:
            del self.user_interactions[hashed_user_id]

    def get_all_users(self):
        """Returns a list of all hashed user IDs."""
        return list(self.user_interactions.keys())

if __name__ == '__main__':
    tracker = InteractionTracker()

    # Example Usage
    user_id_1 = 123
    user_id_2 = "user456"

    tracker.track_interaction(user_id_1, "like", {"item_id": 789})
    tracker.track_interaction(user_id_1, "rating", {"item_id": 789, "rating": 4})
    tracker.track_interaction(user_id_2, "upload", {"file_name": "document.pdf", "file_size": 1024})
    tracker.track_interaction(user_id_2, "settings_change", {"setting_name": "email", "old_value": "old@example.com", "new_value": "new@example.com"})
    tracker.track_interaction(user_id_2, "settings_change", {"setting_name": "password", "old_value": "hashed_old", "new_value": "hashed_new"})

    print("User 1 Interactions:", tracker.get_user_interactions(user_id_1))
    print("User 2 Interactions:", tracker.get_user_interactions(user_id_2))
    print("All Likes:", tracker.get_all_interactions_by_type("like"))
    print("Interaction Types:", tracker.get_interaction_types())

    tracker.clear_user_data(user_id_1)
    print("User 1 Interactions after clearing:", tracker.get_user_interactions(user_id_1))
    print("All Users:", tracker.get_all_users())

