import hashlib
import time
import uuid
from collections import defaultdict

class InteractionTracker:
    def __init__(self):
        self.user_interactions = defaultdict(list)  # {anonymized_user_id: [interaction_data]}
        self.interaction_types = set()

    def anonymize_user_id(self, user_id):
        """Hashes the user ID to protect privacy."""
        hashed_id = hashlib.sha256(str(user_id).encode('utf-8')).hexdigest()
        return hashed_id

    def track_interaction(self, user_id, interaction_type, interaction_data=None):
        """
        Tracks a user interaction.

        Args:
            user_id: The ID of the user performing the interaction.
            interaction_type: The type of interaction (e.g., "like", "rating", "upload").
            interaction_data: Optional data associated with the interaction (e.g., rating value, file name).
        """
        if not isinstance(interaction_type, str):
            raise ValueError("Interaction type must be a string.")

        self.interaction_types.add(interaction_type)
        anonymized_user_id = self.anonymize_user_id(user_id)

        interaction_record = {
            'timestamp': time.time(),
            'interaction_type': interaction_type,
            'interaction_data': self.anonymize_data(interaction_data) if interaction_data else None,
            'interaction_id': str(uuid.uuid4()) # Unique ID for each interaction
        }

        self.user_interactions[anonymized_user_id].append(interaction_record)

    def anonymize_data(self, data):
        """
        Anonymizes sensitive data within the interaction data.  This is a placeholder;
        implement more sophisticated anonymization techniques as needed.
        """
        if isinstance(data, str):
            # Example: Hash potentially identifying strings
            return hashlib.sha256(data.encode('utf-8')).hexdigest()
        elif isinstance(data, dict):
            anonymized_dict = {}
            for key, value in data.items():
                anonymized_dict[key] = self.anonymize_data(value)
            return anonymized_dict
        elif isinstance(data, list):
            return [self.anonymize_data(item) for item in data]
        else:
            return data  # Return as is if no anonymization needed

    def get_user_interactions(self, user_id):
        """
        Retrieves interactions for a given user.

        Args:
            user_id: The ID of the user.

        Returns:
            A list of interaction records for the user, or an empty list if no interactions found.
        """
        anonymized_user_id = self.anonymize_user_id(user_id)
        return self.user_interactions.get(anonymized_user_id, [])

    def get_interaction_summary(self):
        """
        Provides a summary of interactions.  Can be extended for more detailed analysis.
        """
        summary = {}
        for interaction_type in self.interaction_types:
            summary[interaction_type] = 0

        for user_id, interactions in self.user_interactions.items():
            for interaction in interactions:
                summary[interaction['interaction_type']] = summary.get(interaction['interaction_type'], 0) + 1
        return summary

    def clear_user_data(self, user_id):
        """
        Deletes all interaction data for a given user.  Important for privacy compliance.
        """
        anonymized_user_id = self.anonymize_user_id(user_id)
        if anonymized_user_id in self.user_interactions:
            del self.user_interactions[anonymized_user_id]

    def get_all_interaction_types(self):
        """Returns a set of all interaction types."""
        return set(self.interaction_types)

if __name__ == '__main__':
    tracker = InteractionTracker()

    # Example Usage
    user_id_1 = 123
    user_id_2 = 456

    tracker.track_interaction(user_id_1, "like", {"item_id": "abc", "timestamp": time.time()})
    tracker.track_interaction(user_id_1, "rating", {"item_id": "def", "rating_value": 4})
