import hashlib
import time
import uuid

class Interaction:
    def __init__(self, user_id, interaction_type, timestamp=None, data=None):
        self.user_id = self._hash_user_id(user_id)  # Hash user ID for privacy
        self.interaction_type = interaction_type
        self.timestamp = timestamp or time.time()
        self.data = self._anonymize_data(data) if data else {}

    def _hash_user_id(self, user_id):
        """Hashes the user ID using SHA-256 for privacy."""
        user_id_str = str(user_id).encode('utf-8')
        return hashlib.sha256(user_id_str).hexdigest()

    def _anonymize_data(self, data):
        """Anonymizes sensitive data within the interaction data."""
        anonymized_data = {}
        for key, value in data.items():
            if key.lower() in ["name", "email", "address", "phone"]:
                anonymized_data[key] = "ANONYMIZED"  # Replace sensitive info
            elif key.lower() == "text":
                anonymized_data[key] = self._hash_text(value) #Hash text
            else:
                anonymized_data[key] = value
        return anonymized_data

    def _hash_text(self, text):
        """Hashes text data using SHA-256."""
        text_str = str(text).encode('utf-8')
        return hashlib.sha256(text_str).hexdigest()

    def __repr__(self):
        return (f"Interaction(user_id='{self.user_id[:8]}...', "
                f"interaction_type='{self.interaction_type}', "
                f"timestamp={self.timestamp}, "
                f"data={self.data})")


class InteractionEngine:
    def __init__(self):
        self.interactions = []
        self.user_interaction_counts = {} # Track interaction counts per user

    def record_interaction(self, user_id, interaction_type, data=None):
        """Records a new user interaction."""
        interaction = Interaction(user_id, interaction_type, data=data)
        self.interactions.append(interaction)

        hashed_user_id = interaction.user_id
        if hashed_user_id not in self.user_interaction_counts:
            self.user_interaction_counts[hashed_user_id] = 0
        self.user_interaction_counts[hashed_user_id] += 1

    def get_user_interactions(self, user_id):
        """Retrieves all interactions for a given user (hashed ID)."""
        hashed_user_id = Interaction(user_id, "dummy").user_id #Hash the input user_id for comparison
        return [
            interaction
            for interaction in self.interactions
            if interaction.user_id == hashed_user_id
        ]

    def get_interaction_count(self, user_id):
        """Returns the number of interactions for a given user."""
        hashed_user_id = Interaction(user_id, "dummy").user_id
        return self.user_interaction_counts.get(hashed_user_id, 0)

    def get_all_interactions(self):
        """Returns all interactions recorded."""
        return self.interactions

    def anonymize_user_data(self, user_id):
        """Anonymizes all data associated with a user."""
        hashed_user_id = Interaction(user_id, "dummy").user_id
        for interaction in self.interactions:
            if interaction.user_id == hashed_user_id:
                interaction.data = {}  # Remove all data
                interaction.user_id = str(uuid.uuid4()) #Replace with a random UUID

    def clear_user_data(self, user_id):
        """Removes all interactions associated with a user."""
        hashed_user_id = Interaction(user_id, "dummy").user_id
        self.interactions = [
            interaction
            for interaction in self.interactions
            if interaction.user_id != hashed_user_id
        ]
        if hashed_user_id in self.user_interaction_counts:
            del self.user_interaction_counts[hashed_user_id]

