import re
import hashlib

class DataStore:
    def __init__(self):
        self.data = {}
        self.allowed_types = {
            "text": self._sanitize_text,
            "number": self._sanitize_number,
            "email": self._sanitize_email,
            "url": self._sanitize_url
        }

    def _sanitize_text(self, text):
        """Sanitizes text input by removing special characters and limiting length."""
        text = re.sub(r"[^a-zA-Z0-9\s]", "", text)  # Remove special characters
        return text[:255]  # Limit length

    def _sanitize_number(self, number):
        """Sanitizes number input by ensuring it's a valid number."""
        try:
            return float(number)
        except ValueError:
            return None

    def _sanitize_email(self, email):
        """Sanitizes email input by validating format."""
        if re.match(r"[^@]+@[^@]+\.[^@]+", email):
            return email[:255]
        else:
            return None

    def _sanitize_url(self, url):
        """Sanitizes URL input by validating format."""
        if re.match(r"https?://(?:[-\w.]|(?:%[\da-fA-F]{2}))+", url):
            return url[:255]
        else:
            return None

    def add_data(self, key, value, data_type="text"):
        """Adds data to the store after sanitizing and hashing."""
        if data_type in self.allowed_types:
            sanitized_value = self.allowed_types[data_type](value)
            if sanitized_value is not None:
                hashed_value = hashlib.sha256(str(sanitized_value).encode()).hexdigest()
                self.data[key] = hashed_value
        else:
            print(f"Invalid data type: {data_type}")

    def get_data(self, key):
        """Retrieves data from the store (hashed)."""
        return self.data.get(key)

    def remove_data(self, key):
        """Removes data from the store."""
        if key in self.data:
            del self.data[key]

    def update_data(self, key, new_value, data_type="text"):
        """Updates data in the store after sanitizing and hashing."""
        if key in self.data:
            self.add_data(key, new_value, data_type)
        else:
            print(f"Key '{key}' not found.")

    def clear_data(self):
        """Clears all data from the store."""
        self.data = {}

